import React, { useEffect, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import Navbar from './Navbar';
import Bubbles from './Bubbles';
import EnquiryModal from './EnquiryModal';

function Home() {
  const heroRef = useRef(null);
  const posRef = useRef(50);
  const [showModal, setShowModal] = useState(false);

  useEffect(() => {
    let animId;

    function animateBG() {
      posRef.current += 0.02;
      if (heroRef.current) {
        heroRef.current.style.backgroundPosition = `${posRef.current}% center`;
      }
      animId = requestAnimationFrame(animateBG);
    }

    animId = requestAnimationFrame(animateBG);
    return () => cancelAnimationFrame(animId);
  }, []);

  return (
    <>
      <Navbar onEnquire={() => setShowModal(true)} />

      <section className="hero" ref={heroRef}>
        <div className="overlay" />
        <Bubbles />
        <div className="content">
          <p className="tag">Your Perfect Place To Thrive.</p>
          <h1>Yathirai InfoTech</h1>
          <p className="desc">
            A place where students play with skills, explore ideas,
            build confidence, and begin their journey toward knowledge,
            growth, and success.
          </p>
          <Link to="/about" className="explore-btn">Explore</Link>
        </div>
      </section>

      {showModal && <EnquiryModal onClose={() => setShowModal(false)} />}
    </>
  );
}

export default Home;
